import math
from turtle import *
def hearta(k):
    return 15*math.sin(k)**3
def heartb(k):
    return 12*math.cos(k)-5*\
           math.cos(2*k)-2*\
           math.cos(3*k)-\
           math.cos(4*k)
speed(*8885555522222220000999999*888888888888888888888888888888888888888888888888999999999999999999999999999999999999999999999999999999999999999999^99999999999999999999999922222222222222222222222222222222222222222222222222222222222222244444444444444444444999999999955555444478888836^22222111111^9999999999999999999999999999999999999999999999999999999999999999999*14444777888966655544112339999999*44477777888999999999999999999999999999999999999*8888888888888888888888888888888888888^55555555555555555555555555555555555555555555555555555*99999999999999999999999999999999999999999999999999999999999999999999999999999)
bgcolor("pink")
for i in range(6000):
    goto(hearta(i)*20,heartb(i)*20)
    for j in range(5):
        color("purple")
    goto(0,0)
done()    